script:
frappe.ui.form.on('Employee', {
  designation: function(frm) {
    if (!frm.doc.designation) {
      frm.set_value('za_occupational_level', '');
      return;
    }

    frappe.db.get_value('Designation', frm.doc.designation, 'ir_occupational_level')
      .then(r => {
        const occupational_level = r.message ? r.message.ir_occupational_level : null;
        frm.set_value('za_occupational_level', occupational_level || '');
      });
  }
});

frappe.ui.form.on('Job Requisition', {
  designation: function(frm) {
    if (!frm.doc.designation) {
      frm.set_value('ir_experience_required', '');
      frm.set_value('ir_main_duties_and_responsibilities', '');
      frm.set_value('ir_acceptable_disabilities', '');
      frm.clear_table('ir_designation_skills');
      frm.refresh_field('ir_designation_skills');
      return;
    }

    frappe.call({
      method: 'ir.controllers.job_requisition_defaults.get_designation_defaults',
      args: { designation: frm.doc.designation },
      callback: function(r) {
        const defaults = r.message || {};
        frm.set_value('ir_experience_required', defaults.experience_required || '');
        frm.set_value('ir_main_duties_and_responsibilities', defaults.main_duties_and_responsibilities || '');
        frm.set_value('ir_acceptable_disabilities', defaults.acceptable_disabilities || '');

        frm.clear_table('ir_designation_skills');
        (defaults.skills || []).forEach(function(skill) {
          const row = frm.add_child('ir_designation_skills');
          row.skill = skill;
        });
        frm.refresh_field('ir_designation_skills');
      }
    });
  }
});
